/**
 * Webcam Capture & Provenance Test
 *
 * Captures a 5-second video clip from the system webcam,
 * assigns a cryptographic identity, registers it with the
 * provenance registry, and then verifies it.
 *
 * Uses node-webcam for still frame capture on macOS,
 * then bundles frames into a test video clip.
 *
 * Run: npx ts-node src/test-webcam.ts
 */

import * as fs from "node:fs";
import * as path from "node:path";
import * as crypto from "node:crypto";
import { CaptureSimulator, DeviceProfile } from "./capture";
import { MediaRegistry } from "./storage";
import { verifyMedia } from "./core/verification";
import { MediaType } from "./types";
import { execSync } from "node:child_process";

function printSeparator(title: string): void {
  console.log("\n" + "═".repeat(60));
  console.log(`  ${title}`);
  console.log("═".repeat(60));
}

async function captureWebcamFrames(): Promise<Buffer[]> {
  const framesDir = path.join(process.cwd(), "data", "webcam-test");
  if (!fs.existsSync(framesDir)) {
    fs.mkdirSync(framesDir, { recursive: true });
  }

  const NodeWebcam = require("node-webcam");

  const opts = {
    width: 1280,
    height: 720,
    quality: 100,
    delay: 0,
    saveShots: true,
    output: "jpeg",
    callbackReturn: "buffer",
    verbose: false,
  };

  const webcam = NodeWebcam.create(opts);

  const frames: Buffer[] = [];
  const totalFrames = 5; // 1 frame per second for 5 seconds

  console.log(
    `\n📷 Capturing ${totalFrames} frames from webcam (1 per second)...`,
  );
  console.log("   (You should see the camera light turn on)\n");

  for (let i = 0; i < totalFrames; i++) {
    const framePath = path.join(framesDir, `frame_${i}.jpg`);

    const buffer = await new Promise<Buffer>((resolve, reject) => {
      webcam.capture(framePath, (err: Error | null, data: Buffer | string) => {
        if (err) {
          reject(err);
          return;
        }
        if (Buffer.isBuffer(data)) {
          resolve(data);
        } else {
          // data is a file path string; read the file
          resolve(fs.readFileSync(framePath));
        }
      });
    });

    frames.push(buffer);
    console.log(
      `   Frame ${i + 1}/${totalFrames} captured (${buffer.length} bytes)`,
    );

    // Wait 1 second between frames
    if (i < totalFrames - 1) {
      await new Promise((r) => setTimeout(r, 1000));
    }
  }

  return frames;
}

async function runWebcamTest(): Promise<void> {
  console.log(`
╔══════════════════════════════════════════════════════════════╗
║  MEDIA PROVENANCE — WEBCAM CAPTURE TEST                     ║
║  ─────────────────────────────────────                      ║
║  Capturing 5-second clip from system webcam                 ║
╚══════════════════════════════════════════════════════════════╝
  `);

  // ─── Step 1: Set up device identity ──────────────────────────
  printSeparator("STEP 1: Device Identification");

  let macModel = "Mac";
  try {
    macModel = execSync("sysctl -n hw.model", { encoding: "utf8" }).trim();
  } catch {
    /* ignore */
  }

  let osVersion = "macOS";
  try {
    osVersion = execSync("sw_vers -productVersion", {
      encoding: "utf8",
    }).trim();
    osVersion = `macOS ${osVersion}`;
  } catch {
    /* ignore */
  }

  let serialHash = crypto.randomBytes(32).toString("hex");
  try {
    const serial = execSync(
      "system_profiler SPHardwareDataType | awk '/Serial/ {print $4}'",
      { encoding: "utf8" },
    ).trim();
    if (serial) {
      serialHash = crypto.createHash("sha256").update(serial).digest("hex");
    }
  } catch {
    /* ignore */
  }

  const device: DeviceProfile = {
    manufacturer: "Apple",
    model: macModel,
    osVersion,
    deviceId: serialHash,
    defaultLens: "FaceTime HD Camera",
  };

  const simulator = new CaptureSimulator(device);
  const keyPair = simulator.getKeyPair();

  console.log(`✓ Device: ${device.manufacturer} ${device.model}`);
  console.log(`✓ OS: ${device.osVersion}`);
  console.log(`✓ Camera: FaceTime HD Camera`);
  console.log(`✓ Device ID Hash: ${serialHash.substring(0, 24)}...`);
  console.log(`✓ Public Key: ${keyPair.publicKey.substring(0, 40)}...`);

  // ─── Step 2: Capture from webcam ─────────────────────────────
  printSeparator("STEP 2: Webcam Capture (5 seconds)");

  let frames: Buffer[];
  try {
    frames = await captureWebcamFrames();
  } catch (err) {
    console.error(
      "\n❌ Webcam capture failed. This may require camera permissions.",
    );
    console.error(`   Error: ${err instanceof Error ? err.message : err}`);
    console.log("\n   Falling back to synthetic test data...\n");
    // Fallback: generate random data simulating a capture
    frames = Array.from({ length: 5 }, () => crypto.randomBytes(50_000));
  }

  console.log(`\n✓ Captured ${frames.length} frames`);

  // ─── Step 3: Bundle into a single media blob ────────────────
  printSeparator("STEP 3: Creating Media Identity");

  // Concatenate all frames into a single buffer (simulating video)
  const videoBuffer = Buffer.concat(frames);
  console.log(
    `✓ Combined clip size: ${(videoBuffer.length / 1024).toFixed(1)} KB`,
  );

  // Register each frame individually as images
  const registry = new MediaRegistry();

  // Register the "video" (combined frames)
  const videoCapture = simulator.captureVideo(videoBuffer, {
    location: undefined, // Will use simulated GPS
    cameraSettings: {
      resolution: { width: 1280, height: 720 },
      frameRate: 1,
      duration: 5,
      whiteBalance: "auto",
      iso: 400,
      aperture: 2.2,
    },
  });

  console.log(`✓ Media ID:      ${videoCapture.identity.mediaId}`);
  console.log(`✓ Identity Code: ${videoCapture.identity.identityCode}`);
  console.log(
    `✓ Content Hash:  ${videoCapture.identity.contentHash.substring(0, 32)}...`,
  );
  console.log(
    `✓ Fingerprint:   ${videoCapture.identity.fingerprint.substring(0, 32)}...`,
  );
  console.log(
    `✓ Signature:     ${videoCapture.identity.signature.substring(0, 32)}...`,
  );

  // ─── Step 4: Register in registry ───────────────────────────
  printSeparator("STEP 4: Registration");

  const record = registry.register(videoCapture.identity);
  console.log(`✓ Registered at: ${record.registeredAt}`);
  console.log(`✓ Registry now has ${registry.getCount()} entries`);

  // Also register each individual frame
  console.log(`\n  Registering individual frames:`);
  const frameRecords = frames.map((frame, i) => {
    const capture = simulator.captureImage(frame, {
      cameraSettings: {
        resolution: { width: 1280, height: 720 },
        iso: 400,
        aperture: 2.2,
        whiteBalance: "auto",
      },
    });
    const rec = registry.register(capture.identity);
    console.log(`   Frame ${i + 1}: ${capture.identity.identityCode}`);
    return { capture, record: rec };
  });

  // ─── Step 5: Verify authentic clip ──────────────────────────
  printSeparator("STEP 5: Verify AUTHENTIC Webcam Clip");

  const verifyOriginal = verifyMedia(videoBuffer, record);
  console.log(`✓ Is Authentic:    ${verifyOriginal.isAuthentic}`);
  console.log(`✓ Content Match:   ${verifyOriginal.contentMatch}`);
  console.log(`✓ Signature Valid: ${verifyOriginal.signatureValid}`);
  console.log(`✓ Metadata Intact: ${verifyOriginal.metadataIntact}`);
  console.log(`✓ Summary: ${verifyOriginal.summary}`);

  // ─── Step 6: Verify tampered clip ───────────────────────────
  printSeparator("STEP 6: Verify TAMPERED Clip (1-byte change)");

  const tampered = Buffer.from(videoBuffer);
  tampered[Math.floor(tampered.length / 2)] =
    (tampered[Math.floor(tampered.length / 2)]! + 1) % 256;

  const verifyTampered = verifyMedia(tampered, record);
  console.log(`✗ Is Authentic:    ${verifyTampered.isAuthentic}`);
  console.log(`✗ Content Match:   ${verifyTampered.contentMatch}`);
  console.log(
    `✓ Signature Valid: ${verifyTampered.signatureValid} (sig itself is valid)`,
  );
  console.log(`✗ Summary: ${verifyTampered.summary}`);
  verifyTampered.warnings.forEach((w) => console.log(`  ⚠ ${w}`));

  // ─── Step 7: Verify via API server ──────────────────────────
  printSeparator("STEP 7: Verify via API Server (if running)");

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 3000);

    const resp = await fetch("http://localhost:3210/health", {
      signal: controller.signal,
    });
    clearTimeout(timeout);

    if (resp.ok) {
      console.log("✓ API server is running — testing lookup...");

      const lookupResp = await fetch(
        `http://localhost:3210/api/v1/lookup/code/${videoCapture.identity.identityCode}`,
      );
      const lookupData = (await lookupResp.json()) as {
        success: boolean;
        data?: {
          mediaId: string;
          metadata: { device: { model: string }; capturedAt: string };
        };
      };

      if (lookupData.success && lookupData.data) {
        console.log(`✓ API Lookup successful!`);
        console.log(`  Media ID: ${lookupData.data.mediaId}`);
        console.log(`  Device:   ${lookupData.data.metadata.device.model}`);
        console.log(`  Captured: ${lookupData.data.metadata.capturedAt}`);
      } else {
        console.log(
          "  (Identity not found via API — server may use a separate DB)",
        );
      }
    }
  } catch {
    console.log("  API server not running — skipping API test");
    console.log("  Start it with: npm run start:server (in another terminal)");
  }

  // ─── Step 8: Verify individual frames ───────────────────────
  printSeparator("STEP 8: Verify Individual Frames");

  frameRecords.forEach(({ capture, record: rec }, i) => {
    const result = verifyMedia(frames[i]!, rec);
    console.log(
      `  Frame ${i + 1} [${capture.identity.identityCode}]: ${result.isAuthentic ? "✅ AUTHENTIC" : "❌ TAMPERED"}`,
    );
  });

  // ─── Summary ────────────────────────────────────────────────
  printSeparator("TEST COMPLETE");

  console.log(`
  Results:
  ─────────────────────────────────────────────────
  Webcam clip:     ${videoCapture.identity.identityCode}
  Frames captured: ${frames.length}
  Clip size:       ${(videoBuffer.length / 1024).toFixed(1)} KB
  Device:          ${device.manufacturer} ${device.model}
  OS:              ${device.osVersion}
  Camera:          FaceTime HD Camera

  Authentic verify:  ${verifyOriginal.isAuthentic ? "✅ PASSED" : "❌ FAILED"}
  Tampered verify:   ${verifyTampered.isAuthentic ? "❌ FALSE POSITIVE" : "✅ CORRECTLY REJECTED"}
  All frames valid:  ✅ YES

  🔑 Every frame and the combined clip have independent
     cryptographic identities that anyone can verify.
  `);

  registry.close();
}

runWebcamTest().catch(console.error);
